return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.33 && progress < 0.66) stage = 2;
    else if (progress >= 0.66) stage = 3;

    var midX = W / 2;
    var midY = H / 2 - 22;
    var cubeSize = 22;
    var w = cubeSize * 0.866;
    var h = cubeSize * 0.5;
    var size = 2;

    function drawCube(x, y, colorTop, colorLeft, colorRight) {
      // Top face
      ctx.fillStyle = colorTop;
      ctx.beginPath();
      ctx.moveTo(x, y - cubeSize);
      ctx.lineTo(x + w, y - h);
      ctx.lineTo(x, y);
      ctx.lineTo(x - w, y - h);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = '#1F2937';
      ctx.lineWidth = 0.5;
      ctx.stroke();

      // Left face
      ctx.fillStyle = colorLeft;
      ctx.beginPath();
      ctx.moveTo(x - w, y - h);
      ctx.lineTo(x, y);
      ctx.lineTo(x, y + cubeSize);
      ctx.lineTo(x - w, y + cubeSize - h);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      // Right face
      ctx.fillStyle = colorRight;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + w, y - h);
      ctx.lineTo(x + w, y + cubeSize - h);
      ctx.lineTo(x, y + cubeSize);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
    }

    // Draw 2x2x2 stack back-to-front
    for (var dz = 0; dz < size; dz++) {
      for (var dy = 0; dy < size; dy++) {
        for (var dx = 0; dx < size; dx++) {
          var stackOffsetX = (dx - dy) * w;
          var stackOffsetY = (dx + dy) * h - dz * cubeSize;

          var cx = midX + stackOffsetX;
          var cy = midY + stackOffsetY + h * 0.4;

          drawCube(cx, cy, '#34D399', '#10B981', '#047857');
        }
      }
    }

    // Bottom front edge highlight in Stage 2 & 3
    if (stage >= 2) {
      // The bottom front edge runs from the bottom-left point of the stack to the bottom-center point
      // Center point: midX, midY + 2 * h + h * 0.4
      // Front-Right point is at dx=1, dy=0, dz=0:
      // cx = midX + w, cy = midY + h + h * 0.4

      var x1 = midX - w;
      var y1 = midY + h + h * 0.4 + cubeSize;
      var x2 = midX;
      var y2 = midY + 2 * h + h * 0.4 + cubeSize;

      ctx.strokeStyle = '#FBBF24'; // Gold
      ctx.lineWidth = 3.5;
      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      // Draw tick marks at endpoints
      ctx.beginPath();
      ctx.moveTo(x1 - 2, y1 - 4);
      ctx.lineTo(x1 + 2, y1 + 4);
      ctx.moveTo(x2 - 2, y2 - 4);
      ctx.lineTo(x2 + 2, y2 + 4);
      ctx.stroke();
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Volume = 8 Blocks', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('This 3D cube is built with 8 smaller unit cubes.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Edge Length = ³√8 = 2 Blocks', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Taking the cube root finds the side length of the volume.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('Inverse Operation', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Cubing: 2 → 8 (2³). Cube Root: 8 → 2 (³√8).', W / 2, H - 22);
    }
  }
};
